def find_visitor(stu_visit_interface):
    query = QtSql.QSqlQuery()
    query_string = "select `visid`, `name`, `telephone` from `visitor` where `stuid` = :username"

    if(stu_visit_interface.ui.visid.text() != ''):
        query_string = query_string + " and `visid` like :visid"
    if(stu_visit_interface.ui.name.text() != ''):
        query_string = query_string + " and `name` like :name"
    if(stu_visit_interface.ui.telephone.text() != ''):
        query_string = query_string + " and `telephone` like :telephone"

    query.prepare(query_string)
    query.bindValue(':username', stu_visit_interface.stuid)
    query.bindValue(':visid', '%' + stu_visit_interface.ui.visid.text() + '%')
    query.bindValue(':name', '%' + stu_visit_interface.ui.name.text() + '%')
    query.bindValue(':telephone', '%' + stu_visit_interface.ui.telephone.text() + '%')
    query.exec()

    stu_visit_interface.ui.visitor_table.setRowCount(0)
    
    while query.next():
        stu_visit_interface.ui.visitor_table.insertRow(stu_visit_interface.ui.visitor_table.rowCount())
        i = stu_visit_interface.ui.visitor_table.rowCount() - 1
        stu_visit_interface.ui.visitor_table.setItem(i, 0, QtWidgets.QTableWidgetItem(query.value(0)))
        stu_visit_interface.ui.visitor_table.setItem(i, 1, QtWidgets.QTableWidgetItem(query.value(1)))
        stu_visit_interface.ui.visitor_table.setItem(i, 2, QtWidgets.QTableWidgetItem(query.value(2)))

