def find_reservation(stu_visit_interface):
    query = QtSql.QSqlQuery()
    query_string = "select `resid`, `visid`, `date`, `reason` from `reservation` where `stuid` = :username and `date` >= curdate()"

    if(stu_visit_interface.ui.resid.text().isdigit()):
        query_string = query_string + " and `resid` = :resid"
    if(stu_visit_interface.ui.visid.text() != ''):
        query_string = query_string + " and `visid` like :visid"
    if(stu_visit_interface.ui.year.text() != ''):
        query_string = query_string + " and year(`date`) = :year"
    if(stu_visit_interface.ui.month.text() != ''):
        query_string = query_string + " and month(`date`) = :month"
    if(stu_visit_interface.ui.day.text() != ''):
        query_string = query_string + " and day(`date`) = :day"
    if(stu_visit_interface.ui.reason.toPlainText() != ''):
        query_string = query_string + " and `reason` like :reason"

    query.prepare(query_string)
    query.bindValue(':username', stu_visit_interface.stuid)
    if(stu_visit_interface.ui.resid.text() != '' and stu_visit_interface.ui.resid.text().isdigit()):
        query.bindValue(':resid', int(stu_visit_interface.ui.resid.text()))
    query.bindValue(':visid', '%' + stu_visit_interface.ui.visid.text() + '%')
    query.bindValue(':year', stu_visit_interface.ui.year.text())
    query.bindValue(':month', stu_visit_interface.ui.month.text())
    query.bindValue(':day', stu_visit_interface.ui.day.text())
    query.bindValue(':reason', '%' + stu_visit_interface.ui.reason.toPlainText() + '%')
    query.exec()

    stu_visit_interface.ui.res_table.setRowCount(0)
    
    while query.next():
        stu_visit_interface.ui.res_table.insertRow(stu_visit_interface.ui.res_table.rowCount())
        i = stu_visit_interface.ui.res_table.rowCount() - 1
        stu_visit_interface.ui.res_table.setItem(i, 0, QtWidgets.QTableWidgetItem(str(query.value(0))))
        stu_visit_interface.ui.res_table.setItem(i, 1, QtWidgets.QTableWidgetItem(query.value(1)))
        stu_visit_interface.ui.res_table.setItem(i, 2, QtWidgets.QTableWidgetItem(decode_date(query.value(2))))
        stu_visit_interface.ui.res_table.setItem(i, 3, QtWidgets.QTableWidgetItem(query.value(3)))

def add_reservation(stu_visit_interface):
    if(stu_visit_interface.ui.visid.text() == '' or not stu_visit_interface.ui.year.text().isdigit() or not stu_visit_interface.ui.month.text().isdigit() or not stu_visit_interface.ui.day.text().isdigit() or stu_visit_interface.ui.reason.toPlainText() == ''):
        error_msgbox = QtWidgets.QDialog()
        error_msgbox.setAttribute(QtCore.Qt.WA_DeleteOnClose, True)
        error_msgbox.ui = Ui_error_box()
        error_msgbox.ui.setupUi(error_msgbox, "必须提供有效信息")
        error_msgbox.exec_()
    else:
        query = QtSql.QSqlQuery()
        query.prepare("call add_reservation(:username, :visid, :date, :reason, @stat)")
        query.bindValue(':date', encode_date(stu_visit_interface.ui.year.text(), stu_visit_interface.ui.month.text(), stu_visit_interface.ui.day.text()))
        query.bindValue(':username', stu_visit_interface.stuid)
        query.bindValue(':visid', stu_visit_interface.ui.visid.text())
        query.bindValue(':reason', stu_visit_interface.ui.reason.toPlainText())
        query.exec()
        query.exec("select @stat")
        query.next()

        if (query.value(0) > 0):
            error_msgbox = QtWidgets.QDialog()
            error_msgbox.setAttribute(QtCore.Qt.WA_DeleteOnClose, True)
            error_msgbox.ui = Ui_error_box()
            error_msgbox.ui.setupUi(error_msgbox, "无法新增预约")
            error_msgbox.exec_()
        else:
            find_reservation(stu_visit_interface)

def update_reservation(stu_visit_interface):
    if(not stu_visit_interface.ui.resid.text().isdigit()):
        error_msgbox = QtWidgets.QDialog()
        error_msgbox.setAttribute(QtCore.Qt.WA_DeleteOnClose, True)
        error_msgbox.ui = Ui_error_box()
        error_msgbox.ui.setupUi(error_msgbox, "预约号无效")
        error_msgbox.exec_()
    else:
        query = QtSql.QSqlQuery()
        if (not stu_visit_interface.ui.year.text().isdigit() or not stu_visit_interface.ui.month.text().isdigit() or not stu_visit_interface.ui.day.text().isdigit()):
            query.prepare("call update_reservation(:resid, :username, :visid, null, :reason, @stat)")
        else:
            query.prepare("call update_reservation(:resid, :username, :visid, :date, :reason, @stat)")
            query.bindValue(':date', encode_date(stu_visit_interface.ui.year.text(), stu_visit_interface.ui.month.text(), stu_visit_interface.ui.day.text()))
        query.bindValue(':resid', int(stu_visit_interface.ui.resid.text()))
        query.bindValue(':username', stu_visit_interface.stuid)
        query.bindValue(':visid', stu_visit_interface.ui.visid.text())
        query.bindValue(':reason', stu_visit_interface.ui.reason.toPlainText())
        query.exec()
        query.exec("select @stat")
        query.next()

        if (query.value(0) > 0):
            error_msgbox = QtWidgets.QDialog()
            error_msgbox.setAttribute(QtCore.Qt.WA_DeleteOnClose, True)
            error_msgbox.ui = Ui_error_box()
            error_msgbox.ui.setupUi(error_msgbox, "预约信息更新失败")
            error_msgbox.exec_()
        else:
            find_reservation(stu_visit_interface)

